module eight_bit_adder (
    input [7:0] A,       // First 8-bit input
    input [7:0] B,       // Second 8-bit input
    output [7:0] SUM,    // 8-bit sum output
    output COUT          // Carry out output
);
      wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign {COUT, SUM} = {_n01, _n02, _n03, _n04}; // Perform addition
endmodule
